    border-color: var(--bg-glass-border);
}
.visited-profile-top-row{
    display: flex;
    align-items: center;
    justify-content: space-between;
    width: 100%;
}
.profile-avatar-ring.badge-ring-legend{
    border: 3px solid #FFD700;
    box-shadow: 0 0 18px 4px rgba(255, 215, 0, 0.35), inset 0 0 12px rgba(255, 215, 0, 0.15);
    opacity: 1;
}
.profile-avatar-ring.badge-ring-og{
    border: 3px solid #9B59FF;
    box-shadow: 0 0 18px 4px rgba(155, 89, 255, 0.35), inset 0 0 12px rgba(155, 89, 255, 0.15);
    opacity: 1;
}
.visited-profile-image{
    position: relative;
    border-radius: 50%;
    object-fit: cover;
    width: 120px;
    height: 120px;
    transition: transform 0.3s ease, box-shadow 0.3s ease;
}
.profile-avatar-ring:hover .visited-profile-image{
    transform: scale(1.04);
    box-shadow: 0 4px 20px rgba(0, 0, 0, 0.12);
}
.visited-profile-stats-container{
    display: flex;
    flex-direction: column;
    align-items: flex-end;
    gap: 0.4rem;
