    background-color: var(--bg-glass-border);
    box-shadow: 0 2px 12px rgba(0, 0, 0, 0.05);
}
.visited-profile-stat-item{
    display: flex;
    align-items: baseline;
    gap: 0.4rem;
}
.visited-stat-number{
    font-family: "Lexend Deca", sans-serif;
    font-size: 1.5rem;
    font-weight: 700;
    letter-spacing: -0.02em;
}
.visited-stat-label{
    font-family: var(--font-ui);
    font-size: 0.8rem;
    font-weight: 500;
    opacity: 0.65;
}
.visited-profile-name-container{
