    gap: 0.3rem;
    flex-wrap: wrap;
}
.badge-pill{
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 0.15rem 0.6rem;
    border-radius: 20px;
    font-family: "Lexend Deca", sans-serif;
    font-size: 0.7rem;
    font-weight: 700;
    letter-spacing: 0.02em;
    line-height: 1.4;
