224→const isPrivateIpv4Address = (ip) => {
225→    const parts = ip.split('.').map((part) => Number(part));
226→    if (parts.length !== 4 || parts.some((part) => !Number.isInteger(part) || part < 0 || part > 255)) {
227→        return true;
228→    }
229→
230→    const [a, b] = parts;
231→    if (a === 10 || a === 127 || a === 0) return true;
232→    if (a === 169 && b === 254) return true;
233→    if (a === 172 && b >= 16 && b <= 31) return true;
234→    if (a === 192 && b === 168) return true;
235→    return false;
236→};
237→
238→const isPrivateIpv6Address = (ip) => {
239→    const normalized = ip.toLowerCase();
240→    return (
241→        normalized === '::1' ||
242→        normalized.startsWith('fc') ||
243→        normalized.startsWith('fd') ||
244→        normalized.startsWith('fe80:')
245→    );
246→};
247→
248→const isPrivateIpAddress = (ip) => {
249→    const ipVersion = net.isIP(ip);
250→    if (ipVersion === 4) return isPrivateIpv4Address(ip);
251→    if (ipVersion === 6) return isPrivateIpv6Address(ip);
252→    return true;
253→};
254→
255→const isSafeRemoteImageUrl = (imageUrl) => {
256→    try {
257→        const parsed = new URL(imageUrl);
258→        if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
259→            return false;
260→        }
261→
262→        const hostname = parsed.hostname.toLowerCase();
263→        if (!hostname || hostname === 'localhost' || hostname.endsWith('.local') || hostname.endsWith('.internal')) {
264→            return false;
265→        }
266→
267→        if (net.isIP(hostname) && isPrivateIpAddress(hostname)) {
268→            return false;
269→        }
270→
271→        return true;
272→    } catch {
273→        return false;
274→    }
275→};
276→
277→const evaluateShareImageCandidate = (rawUrl) => {
278→    const absoluteUrl = resolveAbsoluteHttpUrl(rawUrl);
279→    if (!absoluteUrl) {
280→        return {
281→            ok: false,
282→            reason: 'invalid_or_non_http_url',
283→            resolvedUrl: null,
284→        };
285→    }
286→
287→    let path = '';
288→    try {
289→        const parsed = new URL(absoluteUrl);
290→        path = String(parsed.pathname || '').toLowerCase();
291→    } catch {
292→        return {
293→            ok: false,
294→            reason: 'invalid_resolved_url',
295→            resolvedUrl: null,
296→        };
297→    }
298→
299→    if (path.endsWith('.svg')) {
300→        return {
301→            ok: false,
302→            reason: 'svg_not_supported_for_share_image',
303→            resolvedUrl: absoluteUrl,
304→        };
305→    }
306→
307→    if (!isSafeRemoteImageUrl(absoluteUrl)) {
308→        return {
309→            ok: false,
310→            reason: 'unsafe_remote_url',
311→            resolvedUrl: absoluteUrl,
312→        };
313→    }
314→
315→    return {
316→        ok: true,
317→        reason: 'ok',
318→        resolvedUrl: absoluteUrl,
319→    };
320→};
321→
322→const fetchRemoteImageBuffer = async (imageUrl) => {
323→    const controller = new AbortController();
324→    const timeout = setTimeout(() => controller.abort(), REMOTE_IMAGE_FETCH_TIMEOUT_MS);
325→
326→    try {
327→        const response = await fetch(imageUrl, {
328→            method: 'GET',
329→            redirect: 'follow',
330→            signal: controller.signal,
331→            headers: {
332→                Accept: 'image/*,*/*;q=0.8',
333→                'Accept-Encoding': 'identity',
334→                'User-Agent': SHARE_IMAGE_FETCH_USER_AGENT,
335→            },
336→        });
337→
338→        if (!response.ok) {
339→            throw new Error(`upstream image status ${response.status}`);
340→        }
341→
342→        const finalUrl = response.url || imageUrl;
343→        if (!isSafeRemoteImageUrl(finalUrl)) {
344→            throw new Error('upstream redirected to unsafe url');
345→        }
346→
347→        const contentType = String(response.headers.get('content-type') || '').toLowerCase();
348→        if (!contentType.startsWith('image/')) {
349→            throw new Error(`upstream content-type ${contentType || 'unknown'} is not an image`);
350→        }
351→        if (contentType.includes('image/svg')) {
352→            throw new Error('svg images are not used for share previews');
353→        }
354→
355→        const headerContentLength = Number(response.headers.get('content-length'));
356→        if (Number.isFinite(headerContentLength) && headerContentLength > REMOTE_IMAGE_MAX_BYTES) {
357→            throw new Error(`upstream content-length exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
358→        }
359→
360→        const arrayBuffer = await response.arrayBuffer();
361→        const buffer = Buffer.from(arrayBuffer);
362→
363→        if (!buffer.length) {
364→            throw new Error('upstream image is empty');
365→        }
366→        if (buffer.length > REMOTE_IMAGE_MAX_BYTES) {
367→            throw new Error(`upstream image exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
368→        }
369→
370→        return {
371→            buffer,
372→            contentType,
373→            byteLength: buffer.length,
374→            finalUrl,
375→        };
376→    } finally {
377→        clearTimeout(timeout);
378→    }
379→};
