381→const convertToOgJpeg = async (inputBuffer) => {
382→    return sharp(inputBuffer, { limitInputPixels: 60_000_000 })
383→        .rotate()
384→        .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT, {
385→            fit: 'contain',
386→            background: { r: 255, g: 255, b: 255, alpha: 1 },
387→        })
388→        .jpeg({ quality: 82, mozjpeg: true })
389→        .toBuffer();
390→};
